/**
 * event
 * @name onpageload
 * @description
 */
scwin.onpageload = function () {
  scwin.f_DefaultValue();
  rd_prttype.setValue("K");
  lc_dateTitle.setValue("LADEN ON BOARD");
  let v_linkcheck = $c.data.getParameter($p, "linkcheck") ?? ""; //  0:default,1:Booking Search,2:House Search,3:Master Search,4: Booking,5:House,6:master
  scwin.f_getParametrSetting(v_linkcheck); // link처리
};

/**
 * event
 * @name f_getParametrSetting
 * @description Parameter Setting
 */
scwin.f_getParametrSetting = async function (gubun) {
  if (gubun !== "5") {
    // House B/L에서 옴.
    return;
  }
  let v_mhno = $c.data.getParameter($p, "mhno") ?? "";
  let v_blno = $c.data.getParameter($p, "blno") ?? "";
  if (v_blno == 'null') {
    ed_cnd_hhblno.setValue("");
    ed_cnd_hhblno.focus();
    return;
  }
  scwin.hd_kcomcd = $c.data.getParameter($p, "kcomcd") ?? "";
  ed_cnd_hhblno.setValue(v_blno);
  if (!ds_hmhno.getRowCount()) {
    ds_hmhno.insertRow();
  }
  ds_hmhno.setCellData(0, "code", v_mhno);
  ds_hmhno.setCellData(0, "name", v_mhno);
  acb_cnd_mhno.focus();
  await scwin.f_Retrieve();
};

/**
 * event
 * @name f_DefaultValue
 * @description 초기화
 */
scwin.f_DefaultValue = function () {
  scwin.f_Set("INIT");
  ed_cnd_hhblno.focus();
};

/**
 * event
 * @name f_Set
 * @description 화면세팅
 */
scwin.f_Set = function (gubun) {
  switch (gubun) {
    case "INIT":
      //초기화
      $c.gus.cfDisableBtnOnly($p, [btn_Print, btn_Print6]);
      $c.gus.cfEnableObjects($p, [tbl_Search]); // 조회조건.
      break;
    case "RETRIEVE":
      //조회모드
      $c.gus.cfEnableBtnOnly($p, [btn_Print, btn_Print6]);
      $c.gus.cfEnableObjects($p, [tbl_Search]); // 조회조건.
      break;
    case "SAVE":
      $c.gus.cfDisableBtnOnly($p, [btn_Print, btn_Print6]);
      scwin.f_Set("RETRIEVE");
      break;
  }
};

/**
 * event
 * @name f_Retrieve
 * @description 조회
 */
scwin.f_Retrieve = async function () {
  if (ed_cnd_hhblno.getValue().trim() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["House No 1"]); // @은(는) 필수 입력 항목입니다.
    return;
  }
  acb_cnd_mhno.focus(); // B/L No 빠져나올때 event처리 .

  dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
  dma_retrieve.set("mhno", acb_cnd_mhno.getValue());
  if (acb_cnd_mhno_2 != "") {
    dma_retrieve.set("mhno2", acb_cnd_mhno_2.getValue());
  }
  if (acb_cnd_mhno_3 != "") {
    dma_retrieve.set("mhno3", acb_cnd_mhno_3.getValue());
  }
  if (acb_cnd_mhno_4 != "") {
    dma_retrieve.set("mhno4", acb_cnd_mhno_4.getValue());
  }
  if (acb_cnd_mhno_5 != "") {
    dma_retrieve.set("mhno5", acb_cnd_mhno_5.getValue());
  }

  //실행.
  let e = await $c.sbm.execute($p, sbm_retrieve);
  if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
    return false;
  }
  await scwin.sbm_retrieve_submitdone(e);
  //cmd anable
  $c.gus.cfEnableObjects($p, [ed_cnd_hhblno, acb_cnd_mhno]);
  return true;
};

/**
 * event
 * @name f_FieldClear
 * @description 조회 조건 지우기
 */
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, [ed_cnd_hhblno]);
  ds_hmhno.removeAll(); // DATASET COMBO
};

/**
 * event
 * @name f_Save
 * @description 저장
 */
scwin.f_Save = async function (flag) {
  if (!(await scwin.f_validate())) {
    return;
  }
  if (!(await $c.win.confirm($p, E_MSG_CM_CRM_001))) {
    //저장하시겠습니까?
    return;
  }
  let infoArr = [{
    "hhblnoObj": ed_cnd_hhblno,
    "mhnoObj": acb_cnd_mhno,
    "dltObj": ds_houseblList
  }, {
    "hhblnoObj": ed_cnd_hhblno_2,
    "mhnoObj": acb_cnd_mhno_2,
    "dltObj": ds_houseblList2
  }, {
    "hhblnoObj": ed_cnd_hhblno_3,
    "mhnoObj": acb_cnd_mhno_3,
    "dltObj": ds_houseblList3
  }, {
    "hhblnoObj": ed_cnd_hhblno_4,
    "mhnoObj": acb_cnd_mhno_4,
    "dltObj": ds_houseblList4
  }, {
    "hhblnoObj": ed_cnd_hhblno_5,
    "mhnoObj": acb_cnd_mhno_5,
    "dltObj": ds_houseblList5
  }];
  let tempRow = ds_houseblListTemp.getRowJSON(0);
  for (let info of infoArr) {
    for (let idx = 0; idx < info.dltObj.getRowCount(); idx++) {
      // 저장
      info.dltObj.setCellData(idx, "kcomcd", scwin.hd_kcomcd);
      info.dltObj.setCellData(idx, "hhblno", info.hhblnoObj.getValue());
      info.dltObj.setCellData(idx, "mhno", info.mhnoObj.getValue());
      info.dltObj.setCellData(idx, "hhpaynm", tempRow.hhpaynm);
      info.dltObj.setCellData(idx, "hhp1", tempRow.hhp1);
      info.dltObj.setCellData(idx, "hhp2", tempRow.hhp2);
      info.dltObj.setCellData(idx, "hhp3", tempRow.hhp3);
      info.dltObj.setCellData(idx, "hhp4", tempRow.hhp4);
      info.dltObj.setCellData(idx, "hhp5", tempRow.hhp5);
      info.dltObj.setCellData(idx, "hhp6", tempRow.hhp6);
      info.dltObj.setCellData(idx, "hhp7", tempRow.hhp7);
      // info.dltObj.modifyRowStatus(idx, "C");  // insert 로 변경.
    }
  }
  if (rd_prttype.getValue() == "S") {
    //SURRENDER B/L
    for (let idx = 0; idx < infoArr.length; ++idx) {
      let info = infoArr[idx];
      if (info.hhblnoObj.getValue() != "" && info.dltObj.getCellData(0, "autono") != "SURRENDER") {
        await $c.win.alert($p, "House No " + (idx + 1) + "의  B/L Type이  SURRENDER 아님으로 B/L 발급을 불허합니다.");
        return;
      }
    }
  }
  for (let idx = 0; idx < infoArr.length; ++idx) {
    dma_clntNo.set("hhactcust", infoArr[idx].dltObj.getCellData(0, "hhactcust"));
    let e = await $c.sbm.execute($p, sbm_retrieveMgntClnt);
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
      return;
    }
    if (ds_mgntYn.getCellData(0, "mgntYn") == "Y") {
      await $c.win.alert($p, "House No " + (idx + 1) + "의  Customer는 관리거래처이므로 B/L 발급을 불허합니다.");
      return;
    }
  }

  // 실행
  let e = await $c.sbm.execute($p, sbm_save);
  if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
    return;
  }

  //cmd anable
  $c.gus.cfEnableObjects($p, [ed_cnd_hhblno, acb_cnd_mhno, ed_cnd_hhblno_2, acb_cnd_mhno_2, ed_cnd_hhblno_3, acb_cnd_mhno_3, ed_cnd_hhblno_4, acb_cnd_mhno_4, ed_cnd_hhblno_5, acb_cnd_mhno_5]);
  if (!(await scwin.f_Retrieve())) {
    return;
  }
  scwin.f_Set("SAVE");
  if (flag == 0) {
    await scwin.f_Print(0);
  } else if (flag == 1) {
    await scwin.f_Print(1);
  } //freight 6개 이상일 때 다른 레포트 출력되도록
};

