/**
 * event
 * @name f_MhnoLoading
 * @description MHNO 가져오기
 */
scwin.f_MhnoLoading = function (idx) {
  let infoArr = [{
    "hhblnoObj": ed_cnd_hhblno,
    "dltObj": ds_hmhno,
    "sbmObj": sbm_retriveSeaHouseMhnoListCombo1
  }, {
    "hhblnoObj": ed_cnd_hhblno_2,
    "dltObj": ds_hmhno_2,
    "sbmObj": sbm_retriveSeaHouseMhnoListCombo2
  }, {
    "hhblnoObj": ed_cnd_hhblno_3,
    "dltObj": ds_hmhno_3,
    "sbmObj": sbm_retriveSeaHouseMhnoListCombo3
  }, {
    "hhblnoObj": ed_cnd_hhblno_4,
    "dltObj": ds_hmhno_4,
    "sbmObj": sbm_retriveSeaHouseMhnoListCombo4
  }, {
    "hhblnoObj": ed_cnd_hhblno_5,
    "dltObj": ds_hmhno_5,
    "sbmObj": sbm_retriveSeaHouseMhnoListCombo5
  }];
  switch (idx) {
    case 1:
    case 2:
    case 3:
    case 4:
    case 5:
      let info = infoArr[idx - 1];
      if (info.hhblnoObj.options.hidVal === info.hhblnoObj.getValue()) {
        break;
      }
      info.hhblnoObj.options.hidVal = info.hhblnoObj.getValue();
      let strClntNo = info.hhblnoObj.getValue().trim();
      if (strClntNo.length) {
        dma_retriveSeaHouseMhnoListCombo.set("param1", strClntNo);
        $c.sbm.execute($p, info.sbmObj);
      } else {
        info.dltObj.removeAll();
      }
      break;
  }
};

