/**
 * event
 * @name f_Print
 * @description 오즈화면
 */
scwin.f_Print = async function (flag) {
  let dataArr = [{
    "hhblno": ed_cnd_hhblno.getValue(),
    "mhno": acb_cnd_mhno.getValue()
  }];
  if (ed_cnd_hhblno_2.getValue() != "") {
    dataArr.push({
      "hhblno": ed_cnd_hhblno_2.getValue(),
      "mhno": acb_cnd_mhno_2.getValue()
    });
  }
  if (ed_cnd_hhblno_3.getValue() != "") {
    dataArr.push({
      "hhblno": ed_cnd_hhblno_3.getValue(),
      "mhno": acb_cnd_mhno_3.getValue()
    });
  }
  if (ed_cnd_hhblno_4.getValue() != "") {
    dataArr.push({
      "hhblno": ed_cnd_hhblno_4.getValue(),
      "mhno": acb_cnd_mhno_4.getValue()
    });
  }
  if (ed_cnd_hhblno_5.getValue() != "") {
    dataArr.push({
      "hhblno": ed_cnd_hhblno_5.getValue(),
      "mhno": acb_cnd_mhno_5.getValue()
    });
  }
  for (let item of dataArr) {
    // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
    // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
    let reportFile;
    if (flag == 0) {
      //2020.03.10 최윤경 팀장 요청 사항 SURRENDER B/L , COPY B/L 추가
      if (rd_prttype.getValue() == "K") {
        //Kiffa
        reportFile = "/il/seaout/se_105_01_03a.ozr";
      } else if (rd_prttype.getValue() == "C") {
        //Check B/L
        reportFile = "/il/seaout/se_105_01_03b.ozr";
      } else if (rd_prttype.getValue() == "S") {
        //SURRENDER B/L
        reportFile = "/il/seaout/se_105_01_03c.ozr";
      } else if (rd_prttype.getValue() == "P") {
        //COPY B/L
        reportFile = "/il/seaout/se_105_01_03d.ozr";
      }
    } else if (flag == 1) {
      if (rd_prttype.getValue() == "K") {
        //Kiffa
        reportFile = "/il/seaout/se_105_01_03a_1.ozr";
      } else if (rd_prttype.getValue() == "C") {
        //Check B/L
        reportFile = "/il/seaout/se_105_01_03b_1.ozr";
      } else if (rd_prttype.getValue() == "S") {
        //SURRENDER B/L
        reportFile = "/il/seaout/se_105_01_03c_1.ozr";
      } else if (rd_prttype.getValue() == "P") {
        //COPY B/L
        reportFile = "/il/seaout/se_105_01_03d_1.ozr";
      }
    }
    let filename = item.hhblno;
    switch (rd_prttype.getValue()) {
      case "K":
        //Kiffa
        filename += "_IMAGE BL";
        break;
      case "C":
        //Check B/L
        filename += "_CHECK BL";
        break;
      case "S":
        //SURRENDER B/L
        filename += "_SURRENDER BL";
        break;
      case "P":
        //COPY B/L
        filename += "_COPY BL";
        break;
    }
    let data = {
      odiName: "se_105_01_03",
      reportName: reportFile,
      odiParam: {
        "odiName": "se_105_01_03",
        "KCOMCD": scwin.hd_kcomcd,
        "HHBLNO": item.hhblno,
        "MHNO": item.mhno,
        "ONBOARD": lc_dateTitle.getValue(),
        "PAYAT": lc_hhpaynm.getValue(),
        "RMK": chb_bank.getValue() === "1" ? "1" : "0",
        "USERID": $c.data.getMemInfo($p, "userId") ?? ""
      },
      viewerParam: {
        "useprogressbar": false,
        // 프로그레스바 쓸지 말지
        "mode": "preview",
        //preview, print, export
        "export.filename": filename,
        "export.format": "pdf",
        "export.path": "C:\\OZExport"
      },
      formParam: {}
    };
    let opts = {
      id: "ozReportPopup" + Date.now(),
      popupName: "오즈 리포트",
      modal: false,
      type: "browserPopup",
      width: 1000,
      height: 830,
      title: "오즈 리포트"
    };
    await $c.win.openPopup($p, "/ui/cm/zz/ozreportPopup.xml", opts, data);
  }
};

/**
 * event
 * @name f_RunExcel
 * @description 엑셀 다운로드
 */
scwin.f_RunExcel = async function (v_tab) {
  let infoArr = [{
    "dltObj": ds_houseblList,
    "grdObj": gr_houseblList
  }, {
    "dltObj": ds_houseblList2,
    "grdObj": gr_houseblList2
  }, {
    "dltObj": ds_houseblList3,
    "grdObj": gr_houseblList3
  }, {
    "dltObj": ds_houseblList4,
    "grdObj": gr_houseblList4
  }, {
    "dltObj": ds_houseblList5,
    "grdObj": gr_houseblList5
  }];
  let info = infoArr[v_tab];
  if (!info.dltObj.getRowCount()) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
    return;
  }
  if (await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?")) {
    let visible = Number(info.dltObj.getCellData(0, "sellSeq")) == "" ? false : true;
    if (!visible) {
      return;
    }
    const options = {
      "fileName": "House B/L.xlsx",
      "sheetName": "House B/L",
      "startRowIndex": 2,
      "startColumnIndex": 0
    };
    const infoArr = [{
      "rowIndex": 0,
      "colIndex": 0,
      "rowSpan": 1,
      "colSpan": 6,
      "text": "House B/L",
      "textAlign": "center",
      "drawBorder": "false"
    }];
    $c.data.downloadGridViewExcel($p, info.grdObj, options, infoArr);
  }
};

