/**
 * event
 * @name sbm_retrieve_submitdone
 * @description
 */
scwin.sbm_retrieve_submitdone = async function (e) {
  if (ds_houseblList.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
    scwin.f_Set("INIT");
  } else {
    scwin.f_Set("RETRIEVE");
  }
  if (ds_houseblListTemp.getRowCount()) {
    ds_houseblListTemp.setRowPosition(0);
  }
  let infoArr = [{
    "hhblnoObj": ed_cnd_hhblno,
    "dltObj": ds_houseblList,
    "grdObj": gr_houseblList,
    "totalRows": tbx_totalRows
  }, {
    "hhblnoObj": ed_cnd_hhblno_2,
    "dltObj": ds_houseblList2,
    "grdObj": gr_houseblList2,
    "totalRows": tbx_totalRows2
  }, {
    "hhblnoObj": ed_cnd_hhblno_3,
    "dltObj": ds_houseblList3,
    "grdObj": gr_houseblList3,
    "totalRows": tbx_totalRows3
  }, {
    "hhblnoObj": ed_cnd_hhblno_4,
    "dltObj": ds_houseblList4,
    "grdObj": gr_houseblList4,
    "totalRows": tbx_totalRows4
  }, {
    "hhblnoObj": ed_cnd_hhblno_5,
    "dltObj": ds_houseblList5,
    "grdObj": gr_houseblList5,
    "totalRows": tbx_totalRows5
  }];
  for (let idx = 0; idx < infoArr.length; ++idx) {
    let info = infoArr[idx];
    if (info.hhblnoObj.getValue() == "") {
      tac_houseblList.setLabelText(idx, "House No " + (idx + 1));
    } else {
      tac_houseblList.setLabelText(idx, info.hhblnoObj.getValue());
    }
    info.totalRows.setValue(info.dltObj.getRowCount().toString());
    if (!info.dltObj.getRowCount()) {
      continue;
    } else {
      let visible = Number(info.dltObj.getCellData(0, "sellSeq")) == "" ? false : true;
      if (!visible && info.grdObj.options.autoFit !== "") {
        info.grdObj.clearAutoFit();
      } else if (visible && info.grdObj.options.autoFit === "") {
        info.grdObj.setAutoFit({
          "type": "allColumn"
        });
      }
      info.grdObj.setColumnVisible("chk", visible);
      info.grdObj.setColumnVisible("fareEngCd", visible);
      info.grdObj.setColumnVisible("fareEngNm", visible);
      info.grdObj.setColumnVisible("ppccCls", visible);
      info.grdObj.setColumnVisible("crcCd", visible);
      info.grdObj.setColumnVisible("prtnAmt", visible);
      info.grdObj.setFocusedCell(0, info.grdObj.getFocusedColumnIndex() ?? 0, false);
    }
  }
};

